  ('social-worker-moex-06660', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '非營利組織中，有些組織強調「只有組織、沒有員工」（organizations without people）是採取何種管理學 派的觀點？', '["系統觀點", "環境觀點", "人文觀點", "古典觀點"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "a12893ef6870", "answer_pdf_sha1": "22bc351d55b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
